package main

import (
    "database/sql"
)

// Compliant: Using parameterized queries
func getUserByID(db *sql.DB, userID string) (*User, error) {
    // GOOD: Using parameterized query prevents injection
    query := "SELECT id, name, email FROM users WHERE id = ?"
    row := db.QueryRow(query, userID)

    var user User
    err := row.Scan(&user.ID, &user.Name, &user.Email)
    return &user, err
}

func searchUsers(db *sql.DB, searchTerm string) ([]User, error) {
    // GOOD: Parameterized query with proper placeholder
    query := "SELECT id, name, email FROM users WHERE name LIKE ?"
    searchPattern := "%" + searchTerm + "%"

    rows, err := db.Query(query, searchPattern)
    if err != nil {
        return nil, err
    }
    defer rows.Close()

    var users []User
    for rows.Next() {
        var user User
        if err := rows.Scan(&user.ID, &user.Name, &user.Email); err != nil {
            return nil, err
        }
        users = append(users, user)
    }
    return users, rows.Err()
}

// GOOD: Using prepared statements for repeated queries
func getUserByIDPrepared(db *sql.DB, userID string) (*User, error) {
    stmt, err := db.Prepare("SELECT id, name, email FROM users WHERE id = ?")
    if err != nil {
        return nil, err
    }
    defer stmt.Close()

    row := stmt.QueryRow(userID)
    var user User
    err = row.Scan(&user.ID, &user.Name, &user.Email)
    return &user, err
}
